import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { prefix } from 'utils/prefix';
import Box from 'components/Box';

const propTypes = {
  as: PropTypes.oneOf([
    'button',
    'a',
    'input',
  ]),
  style: PropTypes.shape({}),
  children: PropTypes.node.isRequired,
  className: PropTypes.oneOfType([
    PropTypes.object,
    PropTypes.arrayOf(PropTypes.string),
    PropTypes.string,
  ]),
  to: PropTypes.string,
  type: PropTypes.string,
  theme: PropTypes.oneOf([
    'primary',
    'secondary',
    'success',
    'danger',
    'warning',
    'info',
    'light',
    'dark',
    'link',
  ]),
  outline: PropTypes.bool,
  size: PropTypes.oneOf([
    'sm',
    'lg',
  ]),
  disabled: PropTypes.bool,
  pressed: PropTypes.bool,
  stretchedLink: PropTypes.bool,
  onClick: PropTypes.func,
};

const defaultProps = {
  as: 'button',
  style: null,
  className: null,
  to: null,
  type: 'button',
  theme: 'primary',
  outline: false,
  size: null,
  disabled: false,
  pressed: false,
  stretchedLink: false,
  onClick: null,
};

/**
 * Button component [(Bootstrap Official Documentation)]{@link https://getbootstrap.com/docs/5.1/components/buttons}
 * @component
 * @param {object} props
 * @param {('button'|'a'|'input')} [props.as='button'] - Render button as
 * @param {object} [props.style=null] - React CSS object
 * @param {React.ReactNode} props.children - React children components
 * @param {(string|Array<string>|object)} [props.className=null] - Classnames utility [(Read npmjs.com)]{@link https://www.npmjs.com/package/classnames}
 * @param {string} [props.to=null] - Set link for button
 * @param {string} [props.type="button"] - Change button html tag
 * @param {('primary'|'secondary'|'success'|'danger'|'warning'|'info'|'light'|'dark')} [props.theme="primary"] - Change theme color
 * @param {boolean} [props.disabled=false] - Change disabled state
 * @param {boolean} [props.pressed=false] - Change pressed state
 * @param {boolean} [props.stretchedLink=false] - Add stretched link style
 * @param {function} [props.onClick=null] - Add event hanlder for click
 * @returns {JSX.Element}
 * @example
 * <Button>Button</Button>
 * @author Sedelkov Egor <sedelkovegor@gmail.com>
 * @version 1.0.0
 */
function ButtonBase(props) {
  const {
    as: ComponentType,
    style,
    children,
    className,
    to,
    type,
    theme,
    outline,
    size,
    disabled,
    pressed,
    stretchedLink,
    onClick,
    ...rest
  } = props;

  const BASE_CLASS_NAME = 'btn';

  const classes = classNames(
    BASE_CLASS_NAME,
    {
      [prefix(BASE_CLASS_NAME, outline ? 'outline' : null, theme)]: theme,
      disabled: disabled && ComponentType !== 'button',
      [prefix(BASE_CLASS_NAME, size)]: size,
      active: pressed,
      [prefix('stretched', 'link')]: stretchedLink && ComponentType === 'a',
    },
    className,
  );

  const baseProperties = {
    style,
    className: classes,
    onClick,
    ...rest,
  };

  // for <button />
  const buttonProperties = {
    ...baseProperties,
    type,
    disabled,
  };

  // for <a />
  const linkProperties = {
    ...baseProperties,
    href: to || '#',
    role: 'button',
  };

  // for <input />
  const inputProps = {
    ...baseProperties,
    type,
    value: children,
  };

  if (pressed) {
    buttonProperties['aria-pressed'] = true;
    linkProperties['aria-pressed'] = true;
  }

  if (disabled) {
    linkProperties['aria-disabled'] = true;
  }

  // render as <a />
  if (ComponentType === 'a') {
    return (
      <Box as="a" {...linkProperties}>
        {children}
      </Box>
    );
  }

  // render as <input />
  if (ComponentType === 'input') {
    return (
      <Box as="input" {...inputProps} />
    );
  }

  // default render as <button />
  return (
    <Box as="button" {...buttonProperties}>
      {children}
    </Box>
  );
}

const Button = (props) => <ButtonBase {...props} />;

Button.Primary = (props) => <Button theme="primary" {...props} />;
Button.Secondary = (props) => <Button theme="secondary" {...props} />;
Button.Success = (props) => <Button theme="success" {...props} />;
Button.Danger = (props) => <Button theme="danger" {...props} />;
Button.Warning = (props) => <Button theme="warning" {...props} />;
Button.Info = (props) => <Button theme="info" {...props} />;
Button.Light = (props) => <Button theme="light" {...props} />;
Button.Dark = (props) => <Button theme="dark" {...props} />;

Button.propTypes = propTypes;
Button.defaultProps = defaultProps;

export default Button;
